import React, { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  TextField,
  Button,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  Box,
  MenuItem,
  IconButton,
  Divider,
  Stack,
  Autocomplete,
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import ShoppingCartIcon from '@mui/icons-material/ShoppingCart';
import { API_URL } from '../utils/apiUrl';
import { AuthContext } from '../context/AuthContext';

export default function POSTerminal() {
  const { user } = useContext(AuthContext); // Login kora user context theke
  const [products, setProducts] = useState([]);
  const [customers, setCustomers] = useState([]);
  const [cart, setCart] = useState([]);
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [outlets, setOutlets] = useState([]); // সব আউটলেটের লিস্ট (Superadmin-এর জন্য)
  const [selectedOutletId, setSelectedOutletId] = useState(
    user?.outlet_id || ''
  );

  // 1. Data Fetching
  // const fetchData = async () => {
  //   try {
  //     // User-er outlet ID onujayi products fetch (Backend filter thakte hobe)
  //     const [pRes, cRes] = await Promise.all([
  //       axios.get(
  //         `${API_URL}/api/outlet-products?outlet_id=${user?.outlet_id}`
  //       ),
  //       axios.get(`${API_URL}/api/customers?outlet_id=${user?.outlet_id}`),
  //     ]);
  //     setProducts(pRes.data.data || []);
  //     setCustomers(cRes.data.data || []);
  //   } catch (error) {
  //     console.error('Fetch Error:', error);
  //   }
  // };

  useEffect(() => {
    if (user?.outlet_id) fetchData();
  }, [user]);

  // 2. Cart Logic
  const addToCart = (product) => {
    if (product.stock_quantity <= 0) return alert('Out of stock!');

    const existing = cart.find((item) => item.id === product.id);
    if (existing) {
      if (existing.qty >= product.stock_quantity)
        return alert('Insufficient stock!');
      setCart(
        cart.map((item) =>
          item.id === product.id ? { ...item, qty: item.qty + 1 } : item
        )
      );
    } else {
      setCart([...cart, { ...product, qty: 1 }]);
    }
  };

  const removeFromCart = (id) => setCart(cart.filter((item) => item.id !== id));

  const totalAmount = cart.reduce(
    (sum, item) => sum + item.price * item.qty,
    0
  );

  // 3. Complete Sale (API Hit)
  // const handleCheckout = async () => {
  //   if (!selectedCustomer) return alert('Please select a customer!');
  //   if (cart.length === 0) return alert('Cart is empty!');

  //   const payload = {
  //     outlet_id: user.outlet_id,
  //     user_id: user.id,
  //     customer_id: selectedCustomer.id,
  //     total_amount: totalAmount,
  //     items: cart.map((item) => ({
  //       outlet_product_id: item.id,
  //       qty: item.qty,
  //       unit_price: item.price,
  //     })),
  //   };

  //   try {
  //     await axios.post(`${API_URL}/api/sales`, payload);
  //     alert('Sale Completed Successfully!');
  //     setCart([]);
  //     setSelectedCustomer(null);
  //     fetchData(); // Stock refresh korar jonno
  //   } catch (error) {
  //     alert(error.response?.data?.message || 'Checkout failed');
  //   }
  // };

  const handleCheckout = async () => {
    if (!selectedCustomer) return alert('Please select a customer!');
    if (cart.length === 0) return alert('Cart is empty!');

    // Jodi apnar backend ekbare ektar beshi item nite na pare,
    // tobe cart-er kebol prothom item-ta pathate hobe (ba loop chalate hobe)
    const item = cart[0];

    const payload = {
      outlet_id: Number(user.outlet_id),
      user_id: Number(user.id),
      customer_id: Number(selectedCustomer.id),
      total_amount: Number(totalAmount), // Purapuri cart total
      product_id: Number(item.id), // OutletProduct ID (Prisma model onujayi)
      qty: Number(item.qty),
      unit_price: Number(item.price),
    };

    try {
      await axios.post(`${API_URL}/api/sales`, payload);
      alert('Sale Completed Successfully!');
      setCart([]);
      setSelectedCustomer(null);
      fetchData(); // Stock refresh korbe
    } catch (error) {
      console.error('Sale Error:', error.response?.data);
      alert(
        error.response?.data?.message || 'Validation failed! Check console.'
      );
    }
  };

  const updateQty = (id, delta) => {
    setCart((prevCart) =>
      prevCart.map((item) => {
        if (item.id === id) {
          const newQty = item.qty + delta;
          // Logic: 1 er niche jabe na, ar stock er upore jabe na
          if (newQty >= 1 && newQty <= item.stock_quantity) {
            return { ...item, qty: newQty };
          }
        }
        return item;
      })
    );
  };

  return (
    <Box sx={{ p: 3 }}>
      <Typography variant="h5" sx={{ mb: 3, fontWeight: 'bold' }}>
        POS Terminal - {user?.outlet?.name}
      </Typography>

      <Grid container spacing={3}>
        {/* Left Side: Product List */}
        <Grid item xs={12} md={7}>
          <Grid container spacing={2}>
            {products.map((p) => (
              <Grid item xs={12} sm={6} key={p.id}>
                <Card
                  sx={{ cursor: 'pointer', '&:hover': { boxShadow: 6 } }}
                  onClick={() => addToCart(p)}
                >
                  <CardContent>
                    <Typography variant="subtitle1" fontWeight="bold">
                      {p.product?.name}
                    </Typography>
                    <Typography variant="body2" color="textSecondary">
                      Stock: {p.stock_quantity}
                    </Typography>
                    <Typography variant="h6" color="primary">
                      ৳{p.price}
                    </Typography>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Grid>

        {/* Right Side: Cart & Checkout */}
        <Grid item xs={12} md={5}>
          <Card
            variant="outlined"
            sx={{
              minHeight: '500px',
              display: 'flex',
              flexDirection: 'column',
            }}
          >
            <CardContent sx={{ flexGrow: 1 }}>
              <Typography variant="h6" gutterBottom>
                Current Order
              </Typography>

              {/* Customer Search */}
              <Autocomplete
                options={customers}
                getOptionLabel={(option) => `${option.name} (${option.phone})`}
                onChange={(e, val) => setSelectedCustomer(val)}
                renderInput={(params) => (
                  <TextField
                    {...params}
                    label="Select Customer"
                    fullWidth
                    sx={{ mb: 2 }}
                  />
                )}
              />

              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell>Item</TableCell>
                    <TableCell>Qty</TableCell>
                    <TableCell>Price</TableCell>
                    <TableCell></TableCell>
                  </TableRow>
                </TableHead>
                {/* <TableBody>
                  {cart.map((item) => (
                    <TableRow key={item.id}>
                      <TableCell>{item.product?.name}</TableCell>
                      <TableCell>{item.qty}</TableCell>
                      <TableCell>৳{item.price * item.qty}</TableCell>
                      <TableCell>
                        <IconButton
